"""Byte-identity route: are the held bytes THE SAME DOCUMENT as a location that an authenticated
backend labels publishedVersion / acceptedVersion / submittedVersion? Symmetric — it can CONVICT
(held == submittedVersion => working paper) as readily as it can acquit."""
import json, re, io, time, hashlib, urllib.request, urllib.error
from pathlib import Path
ROOT = Path('/home/polaris/wt/flywheel'); CACHE = ROOT/'cache'/'version_align'; CACHE.mkdir(parents=True, exist_ok=True)
UA = {'User-Agent': 'POLARIS/1.0 (mailto:aldrin.or@c-polarbiotech.com)'}
def nz(s): return re.sub(r'\s+',' ',s or '').strip()
def sh(t,k=8):
    w=nz(t).lower().split(); return {' '.join(w[i:i+k]) for i in range(0,max(0,len(w)-k),3)}
_last=[0.0]
def fetch(u):
    key = CACHE/(hashlib.sha256(u.encode()).hexdigest()[:20]+'.txt')
    if key.exists(): return 'OK', key.read_text()
    w = _last[0]+1.3-time.time()
    if w>0: time.sleep(w)
    _last[0]=time.time()
    try:
        with urllib.request.urlopen(urllib.request.Request(u,headers=UA),timeout=60) as r: raw=r.read()
    except urllib.error.HTTPError as e: return f'HTTP_{e.code}',''
    except Exception as e: return f'ERR_{type(e).__name__}',''
    if raw[:4]==b'%PDF':
        try:
            from pdfminer.high_level import extract_text
            t = extract_text(io.BytesIO(raw)) or ''
        except Exception: return 'PDF_UNPARSEABLE',''
    else:
        h=raw.decode('utf-8','ignore')
        h=re.sub(r'(?is)<(script|style|nav|header|footer|aside)[^>]*>.*?</\1>',' ',h)
        t=re.sub(r'\s{2,}',' ',re.sub(r'<[^>]+>',' ',h)).strip()
    key.write_text(t); return 'OK', t

corpus = json.loads((ROOT/'outputs'/'journal_corpus_content.json').read_text())
align  = {r['idx']: r for r in json.loads((ROOT/'outputs'/'version_alignment.json').read_text())}
TARGETS=[1,23,25,26,33,53,55,57,69,2,16,20,8,52,64]
print(f"{'idx':>3} {'ver_of_matching_loc':>20}  {'cover':>6}  host / url")
print('-'*118)
res={}
for i in TARGETS:
    r=corpus[i]; held=r.get('fulltext') or ''; H=sh(held)
    a=align.get(i,{})
    locs=[]
    for L in (a.get('unpaywall_locations') or []):
        if L.get('url'): locs.append((L.get('version'),'unpaywall',L['url'],L.get('repo')))
    for L in (a.get('openalex_locations') or []):
        if L.get('url') and L.get('is_oa'): locs.append((L.get('version'),'openalex',L['url'],L.get('host')))
    seen=set(); best=None
    for ver,via,url,host in locs:
        if url in seen: continue
        seen.add(url)
        o,t = fetch(url)
        if o!='OK' or len(t.split())<800: continue
        cov = len(H & sh(t))/max(1,len(H))
        if best is None or cov>best[1]: best=(ver,cov,host,url,via)
    if best:
        ver,cov,host,url,via = best
        verdict = ver if cov>0.85 else 'NO_MATCH'
        res[i]=dict(version=ver,cover=round(cov,3),url=url,host=host,via=via) if cov>0.85 else None
        print(f"{i:>3} {str(verdict):>20}  {cov:6.3f}  {str(host)[:30]:30s} {url[:52]}")
    else:
        res[i]=None
        print(f"{i:>3} {'NO_USABLE_LOCATION':>20}  {'-':>6}  (no OA location returned usable bytes)")
json.dump(res, open('/tmp/byteid.json','w'), indent=1)
EOF
